import pytest
import requests

def test_post_valid_allergy_returns_201_and_stores_resource(
    base_url, clinician_token, patient_id, unique_substance
):
    payload = {
        "resourceType": "AllergyIntolerance",
        "patient": {"reference": f"Patient/{patient_id}"},
        "code": {"coding": [{"system": "http://snomed.info/sct",
                              "code": unique_substance}]},
        "clinicalStatus": {"coding": [{"code": "active"}]},
        "verificationStatus": {"coding": [{"code": "confirmed"}]}
    }
    resp = requests.post(
        f"{base_url}/AllergyIntolerance",
        json=payload,
        headers={"Authorization": f"Bearer {clinician_token}"}
    )
    assert resp.status_code == 201, resp.text
    body = resp.json()
    assert body["resourceType"] == "AllergyIntolerance"
    assert body.get("id"), "id must be present"
    location = resp.headers.get("Location") or \
        f"{base_url}/AllergyIntolerance/{body['id']}"
    get_resp = requests.get(
        location,
        headers={"Authorization": f"Bearer {clinician_token}"}
    )
    assert get_resp.status_code == 200
    assert get_resp.json()["id"] == body["id"]

import pytest
import requests

def test_minimum_required_fields_allergy_accepted(
    base_url, clinician_token, patient_id, unique_substance
):
    # Only mandatory FHIR R4 fields for AllergyIntolerance
    payload = {
        "resourceType": "AllergyIntolerance",
        "patient": {"reference": f"Patient/{patient_id}"},
        "code": {
            "coding": [{
                "system": "http://snomed.info/sct",
                "code": unique_substance
            }]
        }
    }
    resp = requests.post(
        f"{base_url}/AllergyIntolerance",
        json=payload,
        headers={"Authorization": f"Bearer {clinician_token}"}
    )
    assert resp.status_code == 201, (
        f"Minimum payload rejected: {resp.status_code} {resp.text}"
    )
    body = resp.json()
    assert body["patient"]["reference"] == f"Patient/{patient_id}"
    codes = [c["code"] for c in
             body.get("code", {}).get("coding", [])]
    assert unique_substance in codes

import pytest
import requests

def test_non_conflicting_medication_produces_no_allergy_warning(
    base_url, clinician_token, patient_id, recorded_allergy,
    non_allergenic_substance
):
    # non_allergenic_substance: a substance code NOT in the patient's allergy list
    med_payload = {
        "resourceType": "MedicationRequest",
        "status": "active",
        "intent": "order",
        "subject": {"reference": f"Patient/{patient_id}"},
        "medicationCodeableConcept": {
            "coding": [{
                "system": "http://snomed.info/sct",
                "code": non_allergenic_substance
            }]
        }
    }
    resp = requests.post(
        f"{base_url}/MedicationRequest",
        json=med_payload,
        headers={"Authorization": f"Bearer {clinician_token}"}
    )
    assert resp.status_code in (200, 201), resp.text
    body = resp.json()
    warnings = (
        body.get("issue") or
        body.get("warnings") or
        body.get("decisionSupport") or []
    )
    allergy_conflicts = [
        w for w in warnings
        if "allerg" in str(w).lower() or "conflict" in str(w).lower()
    ]
    assert len(allergy_conflicts) == 0, (
        f"Unexpected allergy conflict for non-allergen: {allergy_conflicts}"
    )
